import { Component } from '@angular/core';
import { CommonModule, NgClass, NgFor, NgIf } from '@angular/common';
import { Input } from '@angular/core';
import { ConvidadoDTO, ConvidadoForm, ConviteResponse } from 'src/app/features/convite/convite.model';
import { ConviteService } from 'src/app/features/convite/convite.service';
import { ToastService } from 'src/app/shared/components/toast/toast.service';
import { FormsModule } from '@angular/forms';
import { Output, EventEmitter } from '@angular/core';
import { ConfirmModalComponent } from 'src/app/shared/components/confirm-modal/confirm-modal.component';
import { ViewChild } from '@angular/core';

@Component({
  selector: 'app-admin-convidados-tab',
  standalone: true,
  templateUrl: './admin-convidados-tab.component.html',
  styleUrls: ['../../admin.component.scss'],
  imports: [
    CommonModule,
    FormsModule,
    NgIf,
    NgFor,
    NgClass,
    ConfirmModalComponent
  ]
})
export class AdminConvidadosTabComponent {

  constructor(
    private conviteSvc: ConviteService,
    private toastSvc: ToastService,
  ) {}


  showConvidadosForm = false;
  convidadosForm: ConvidadoForm = {
    nome: '', codigoConvite: '',
    status: 'PENDENTE'
  };

  @Input() convites: ConviteResponse[] = [];
  @Output() reload = new EventEmitter<void>();

  @ViewChild('confirmModal')
  confirmModal!: ConfirmModalComponent;

  get confirmados(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'CONFIRMADO').length;
  }

  get pendentes(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'PENDENTE').length;
  }

  get talvez(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'TALVEZ').length;
  }

  get naoVem(): number {
    return this.convites.flatMap(c => c.convidados)
      .filter(g => g.status === 'NAO_VEM').length;
  }

  addConvidado(): void {
    if (!this.convidadosForm.nome.trim() || !this.convidadosForm.codigoConvite) {
      this.toastSvc.error('Preencha nome e selecione um convite.');
      return;
    }

    const dto: ConvidadoDTO = {
      id:            0,
      nome:          this.convidadosForm.nome.trim(),
      codigoConvite: this.convidadosForm.codigoConvite,
      status:        'PENDENTE',
    };

    this.conviteSvc.criarConvidado(dto).subscribe({
      next: () => {
        this.showConvidadosForm = false;
        this.convidadosForm = { nome: '', codigoConvite: '', status: 'PENDENTE' };
        this.toastSvc.success('Convidado adicionado!');
        this.reload.emit();
      },
      error: (err) => {
        console.error('Erro ao criar convidado:', err);
        this.toastSvc.error('Erro ao adicionar convidado.');
      },
    });
  }

  // ── Editar convidado inline ───────────────────────────────
  _editandoConvidadoId: number | null = null;
  convidadoEditForm: ConvidadoForm = { nome: '', status: 'PENDENTE' , codigoConvite: ''};

  abrirEdicaoConvidado(g: ConvidadoDTO): void {
    this._editandoConvidadoId = g.id;
    this.convidadoEditForm = { nome: g.nome, status: g.status, codigoConvite: g.codigoConvite };
  }

  cancelarEdicaoConvidado(): void {
    this._editandoConvidadoId = null;
  }

  _salvandoConvidadoId: number | null = null;


  salvarEdicaoConvidado(g: ConvidadoDTO): void {
    if (!this.convidadoEditForm.nome.trim()) return;

    const dto: ConvidadoDTO = {
      ...g,
      nome:          this.convidadoEditForm.nome.trim(),
      status:        this.convidadoEditForm.status ?? g.status,
      codigoConvite: this.convidadoEditForm.codigoConvite,
    };

    this._salvandoConvidadoId = g.id;

    this.conviteSvc.atualizarConvidado(g.id, dto).subscribe({
      next: () => {
        this._salvandoConvidadoId = null;
        this._editandoConvidadoId = null;
        this.reload.emit();
        this.toastSvc.success('Convidado atualizado!');

      },
      error: () => {
        this._salvandoConvidadoId = null;
        this.toastSvc.error('Erro ao atualizar. Tente novamente.');
      },
    });
  }


  // Editar Convidado----------
  codigoSugestoes: ConviteResponse[] = [];

  filtrarCodigos(event: Event): void {
    const termo = (event.target as HTMLInputElement).value.toUpperCase();
    if (!termo) {
      this.codigoSugestoes = [];
      return;
    }
    this.codigoSugestoes = this.convites.filter(c =>
      c.codigo.includes(termo) || c.familia.toUpperCase().includes(termo)
    );
  }

  selecionarCodigo(c: ConviteResponse): void {
    this.convidadoEditForm.codigoConvite = c.codigo;
    this.codigoSugestoes = [];
  }

  fecharSugestoes(): void {
    // timeout pequeno pra deixar o mousedown do item disparar antes do blur
    setTimeout(() => this.codigoSugestoes = [], 150);
  }

  // ── Remover ──────────────────────────────────

  removerConvidado(conviteId: number, convidadoId: number): void {
    const conv = this.convites.find(c => c.id === conviteId);
    const g    = conv?.convidados.find(x => x.id === convidadoId);

    this.confirmModal.open({
      titulo:   'Remover convidado?',
      mensagem: 'Esta ação não pode ser desfeita.',
      nomeAlvo: g?.nome ?? 'este convidado',
      onConfirmar: () => {
        this.conviteSvc.removerConvidado(convidadoId)
        .subscribe({
          next:  () => {  this.reload.emit(); this.toastSvc.success('Convidado removido.'); },
          error: () => this.toastSvc.error('Erro ao remover convidado.'),
        });
      },
    });
  }

  statusClass(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: 'badge--confirm',
      TALVEZ:     'badge--maybe',
      NAO_VEM:    'badge--decline',
      PENDENTE:   'badge--pending',
    };
    return map[status] ?? '';
  }

  statusLabel(status: string): string {
    const map: Record<string, string> = {
      CONFIRMADO: '✓ Confirmado',
      TALVEZ:     '? Talvez',
      NAO_VEM:    '✗ Não vem',
      PENDENTE:   '⏳ Pendente',
    };
    return map[status] ?? status;
  }

}
<app-confirm-modal #confirmModal></app-confirm-modal>

<div class="section-card card">
<div class="section-card__header">
    <h3 class="section-card__title">Lista de Convidados</h3>
    <button class="btn btn--primary btn--sm" (click)="showConvidadosForm = !showConvidadosForm">
    {{ showConvidadosForm ? '✕ Cancelar' : '+ Novo Convidado' }}
    </button>
</div>

<div class="form-panel" *ngIf="showConvidadosForm">
    <div class="form-panel__grid">
    <div class="form-group">
        <label>Nome *</label>
        <input type="text" [(ngModel)]="convidadosForm.nome" >
    </div>
    <div class="form-group">
        <label>Convite (família) *</label>
        <select [(ngModel)]="convidadosForm.codigoConvite">
        <option value="" disabled>Selecione um convite...</option>
        <option *ngFor="let c of convites" [value]="c.codigo">
            {{ c.codigo }} — {{ c.familia }}
        </option>
        </select>
    </div>
    </div>
    <button class="btn btn--primary" (click)="addConvidado()">✨ Adicionar Convidado</button>
</div>

<div class="summary-bar">
    <div class="summary-bar__item">
    <span class="summary-bar__label">Confirmados</span>
    <span class="summary-bar__value" style="color:#27ae60">{{ confirmados }}</span>
    </div>
    <div class="summary-bar__item">
    <span class="summary-bar__label">Talvez</span>
    <span class="summary-bar__value" style="color:var(--gold)">{{ talvez }}</span>
    </div>
    <div class="summary-bar__item">
    <span class="summary-bar__label">Não vem</span>
    <span class="summary-bar__value" style="color:#e74c3c">{{ naoVem }}</span>
    </div>
    <div class="summary-bar__item">
    <span class="summary-bar__label">Pendentes</span>
    <span class="summary-bar__value" style="color:var(--text-soft)">{{ pendentes }}</span>
    </div>
</div>

<table class="data-table">
    <thead>
    <tr>
        <th>Código</th>
        <th>Família</th>
        <th>Convidado</th>
        <th>Status</th>
        <th>Ações</th>
    </tr>
    </thead>
    <tbody>
    <ng-container *ngFor="let conv of convites">
        <ng-container *ngFor="let g of conv.convidados">

        <!-- linha normal -->
        <tr *ngIf="_editandoConvidadoId !== g.id">
            <td><span class="code-tag">{{ conv.codigo }}</span></td>
            <td>{{ conv.familia }}</td>
            <td>{{ g.nome }}</td>
            <td>
            <span class="badge" [ngClass]="statusClass(g.status)">
                {{ statusLabel(g.status) }}
            </span>
            </td>
            <td style="display:flex; gap:0.4rem; align-items:center;">
                <button class="btn-icon" (click)="abrirEdicaoConvidado(g)" title="Editar">✏️</button>
                <button class="btn-icon btn-icon--danger" (click)="removerConvidado(conv.id, g.id)" title="Remover">✕</button>
            </td>
        </tr>

        <!-- linha de edição inline -->
        <tr *ngIf="_editandoConvidadoId === g.id" class="tr--editing">
            <td style="position: relative;">
            <input class="inline-input"
                    [(ngModel)]="convidadoEditForm.codigoConvite"
                    (input)="filtrarCodigos($event)"
                    (blur)="fecharSugestoes()"
                    placeholder="Buscar código...">

            <div class="codigo-suggestions" 
                *ngIf="codigoSugestoes.length > 0">
                <div class="codigo-suggestion-item"
                    *ngFor="let c of codigoSugestoes"
                    (mousedown)="selecionarCodigo(c)">
                <span class="code-tag">{{ c.codigo }}</span>
                <span>{{ c.familia }}</span>
                </div>
            </div>
            </td>                  
            <td>{{ conv.familia }}</td>
            <td>
            <input class="inline-input" [(ngModel)]="convidadoEditForm.nome" placeholder="Nome">
            </td>
            <td>
            <select class="inline-select" [(ngModel)]="convidadoEditForm.status">
                <option value="CONFIRMADO">✓ Confirmado</option>
                <option value="TALVEZ">? Talvez</option>
                <option value="NAO_VEM">✗ Não vem</option>
                <option value="PENDENTE">⏳ Pendente</option>
            </select>
            </td>
            <td style="display:flex; gap:0.4rem; align-items:center;">
            <button class="btn btn--primary btn--sm"
                    (click)="salvarEdicaoConvidado(g)"
                    [disabled]="_salvandoConvidadoId === g.id">
                {{ _salvandoConvidadoId === g.id ? '⏳' : '💾' }}
            </button>                    
            <button class="btn btn--outline btn--sm" (click)="cancelarEdicaoConvidado()">✕</button>
            </td>
        </tr>

        </ng-container>
    </ng-container>

    <tr *ngIf="convites.length === 0">
        <td colspan="5" class="empty-row">Nenhuma resposta ainda.</td>
    </tr>
    </tbody>
</table>
</div>
